1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	type Item = { type: string; cursed?: boolean; enchantment?: number };
14	type Step = { op: string; items: Item[] };
15	type Input = { steps: Step[] };
16	
17	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
18	const BLOCK_BASE_PREMIUM = 60;
19	const BLOCK_SIZE = 3;
20	
21	const withFirstInsurance = (base: number): number =>
22	  base + base * FIRST_INSURANCE_SURCHARGE_RATE;
23	
24	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
25	
26	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
27	
28	const groupByType = (items: Item[]): Map<string, Item[]> => {
29	  const groups = new Map<string, Item[]>();
30	  for (const item of items) {
31	    const group = groups.get(item.type) ?? [];
32	    group.push(item);
33	    groups.set(item.type, group);
34	  }
35	  return groups;
36	};
37	
38	const componentGroupBasePremium = (group: Item[]): number =>
39	  group.length === BLOCK_SIZE
40	    ? BLOCK_BASE_PREMIUM
41	    : group.reduce((sum, item) => sum + itemBasePremium(item), 0);
42	
43	const sum = (values: number[]): number => values.reduce((a, b) => a + b, 0);
44	
45	const itemsSubtotal = (items: Item[]): number => {
46	  const components = items.filter(isComponent);
47	  const nonComponents = items.filter((item) => !isComponent(item));
48	
49	  const nonComponentPremiums = nonComponents.map((item) => {
50	    const base = itemBasePremium(item);
51	    const curseSurcharge = item.cursed ? base * 0.5 : 0;
52	    const highEnchSurcharge = (item.enchantment ?? 0) >= 5 ? base * 0.3 : 0;
53	    return base + curseSurcharge + highEnchSurcharge + base * FIRST_INSURANCE_SURCHARGE_RATE;
54	  });
55	  const componentGroupPremiums = [...groupByType(components).values()].map(
56	    (group) => withFirstInsurance(componentGroupBasePremium(group)),
57	  );
58	
59	  return sum(nonComponentPremiums) + sum(componentGroupPremiums);
60	};
61	
62	const quotePremium = (step: Step): number => {
63	  return Math.ceil(itemsSubtotal(step.items)) + PROCESSING_FEE;
64	};
65	
66	export const runScenario = (input: unknown): unknown => {
67	  const { steps } = input as Input;
68	  const results = steps.map((step) => ({ premium: quotePremium(step) }));
69	  return { results };
70	};
